#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[1001];
        scanf("%s", s);
        int n = strlen(s);
        int pass_check = 1;

        for (int i = 0; i < n - 1; i += 2) {
            if (s[i] == s[i + 1]) {
                pass_check = 0;
                break;
            }
        }

        if (pass_check) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }

    return 0;
}

